/* eslint-disable */
import React, { useState, useRef } from "react";
import { Link, useHistory } from "react-router-dom";

export default function Forget() {
  const [email, setEmail] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [emailSent, setEmailSent] = useState(false);
  const [focusedInput, setFocusedInput] = useState(null);
  const [emailError, setEmailError] = useState(false);
  const cardRef = useRef(null);
  const history = useHistory();

  // نفس تأثيرات Login.js
  const [rotateX, setRotateX] = useState(0);
  const [rotateY, setRotateY] = useState(0);

  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const mouseX = e.clientX - centerX;
    const mouseY = e.clientY - centerY;
    setRotateY((mouseX / (rect.width / 2)) * 10);
    setRotateX((mouseY / (rect.height / 2)) * -10);
  };

  const handleMouseLeave = () => {
    setRotateX(0);
    setRotateY(0);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !email.includes("@")) {
      setEmailError(true);
      return;
    }
    setEmailError(false);
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      setEmailSent(true);
    }, 2000);
  };

  return (
    <div className="forget-container" style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'sans-serif'
    }}>
      <div ref={cardRef} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} style={{
        transform: `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`,
        transition: 'transform 0.1s ease-out',
        background: 'rgba(255,255,255,0.1)',
        backdropFilter: 'blur(10px)',
        borderRadius: '20px',
        padding: '40px',
        width: '100%',
        maxWidth: '400px',
        boxShadow: '0 25px 45px rgba(0,0,0,0.2)',
        border: '1px solid rgba(255,255,255,0.2)'
      }}>
        {!emailSent ? (
          <>
            <h1 style={{ color: 'white', textAlign: 'center', marginBottom: '10px' }}>Mot de passe oublié ?</h1>
            <p style={{ color: 'rgba(255,255,255,0.7)', textAlign: 'center', marginBottom: '30px' }}>Entrez votre email pour réinitialiser</p>

            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onFocus={() => setFocusedInput("email")}
              onBlur={() => setFocusedInput(null)}
              style={{
                width: '100%',
                padding: '12px',
                marginBottom: '20px',
                borderRadius: '10px',
                border: emailError ? '1px solid #ef4444' : '1px solid rgba(255,255,255,0.2)',
                background: 'rgba(255,255,255,0.1)',
                color: 'white',
                fontSize: '16px',
                outline: 'none'
              }}
            />
            {emailError && <p style={{ color: '#ef4444', fontSize: '12px', marginTop: '-15px', marginBottom: '15px' }}>Email invalide</p>}

            <button
              onClick={handleSubmit}
              disabled={isLoading}
              style={{
                width: '100%',
                padding: '12px',
                background: 'linear-gradient(135deg, #667eea, #764ba2)',
                border: 'none',
                borderRadius: '10px',
                color: 'white',
                fontSize: '16px',
                fontWeight: 'bold',
                cursor: 'pointer',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.02)'}
              onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
            >
              {isLoading ? "Envoi..." : "Envoyer le lien"}
            </button>

            <p style={{ textAlign: 'center', marginTop: '20px' }}>
              <Link to="/auth/login" style={{ color: 'rgba(255,255,255,0.7)', textDecoration: 'none' }}>← Retour à la connexion</Link>
            </p>
          </>
        ) : (
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '64px', marginBottom: '20px' }}>📧</div>
            <h2 style={{ color: 'white', marginBottom: '10px' }}>Vérifiez votre email</h2>
            <p style={{ color: 'rgba(255,255,255,0.7)', marginBottom: '20px' }}>
              Un lien a été envoyé à <strong style={{ color: '#a855f7' }}>{email}</strong>
            </p>
            <button
              onClick={() => history.push("/auth/login")}
              style={{
                width: '100%',
                padding: '12px',
                background: 'linear-gradient(135deg, #667eea, #764ba2)',
                border: 'none',
                borderRadius: '10px',
                color: 'white',
                fontSize: '16px',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              Retour à la connexion
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
